#include<bits/stdc++.h>
using namespace std;
long long n,m;
char s[500010];
struct info
{
    long long cnti,cnto,cntio,cntoi,cntioi;
    info(int a=0,int b=0):cnti(a),cnto(b)
    {
        cntio=cntoi=cntioi=0;
    }
};
info val[500010];
void mergeinfo(info &x,info l,info r)
{
    x.cnti=l.cnti+r.cnti;
    x.cnto=l.cnto+r.cnto;
    x.cntio=l.cntio+r.cntio+l.cnti*r.cnto;
    x.cntoi=l.cntoi+r.cntoi+l.cnto*r.cnti;
    x.cntioi=l.cntioi+r.cntioi+l.cnti*r.cntoi+l.cntio*r.cnti;
}
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        info x;
    }a[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        mergeinfo(a[x].x,a[a[x].lson].x,a[a[x].rson].x);
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].x=val[l];
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long p,info val)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return;
        }
        if(a[x].l==a[x].r)
        {
            a[x].x=val;
            return;
        }
        update(a[x].lson,p,val);
        update(a[x].rson,p,val);
        pushup(x);
    }
    info query(long long x,long long l,long long r)
    {
        if(l<=a[x].l&&a[x].r<=r)
        {
            return a[x].x;
        }
        long long mid=(a[x].l+a[x].r)>>1;
        if(l<=mid&&mid+1<=r)
        {
            info ans;
            mergeinfo(ans,query(a[x].lson,l,r),query(a[x].rson,l,r));
            return ans;
        }
        else if(l<=mid)
        {
            return query(a[x].lson,l,r);
        }
        else
        {
            return query(a[x].rson,l,r);
        }
    }
}t;
int main()
{
    scanf("%lld%lld%s",&n,&m,s+1);
    for(long long i=1;i<=n;i++)
    {
        val[i]=info((int)(s[i]=='I'),(int)(s[i]=='O'));
    }
    t.init(1,n);
    while(m--)
    {
        long long op,x,y;
        char ch;
        scanf("%lld%lld",&op,&x);
        if(op==1)
        {
            cin>>ch;
            s[x]=ch;
            t.update(1,x,info((int)(s[x]=='I'),(int)(s[x]=='O')));
        }
        else
        {
            scanf("%lld",&y);
            printf("%lld\n",t.query(1,x,y).cntioi);
        }
    }
    return 0;
}
